import{_ as n,o as s,c as e,a7 as l}from"./chunks/framework.BPD8m7Vq.js";const d=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"面试笔记/JavaSe/面向对象.md","filePath":"面试笔记/JavaSe/面向对象.md","lastUpdated":1773976621000}'),p={name:"面试笔记/JavaSe/面向对象.md"};function i(r,a,c,t,u,b){return s(),e("div",null,[...a[0]||(a[0]=[l(`<h3 id="怎么理解面向对象-封装继承多态是什么" tabindex="-1">怎么理解面向对象？封装继承多态是什么？ <a class="header-anchor" href="#怎么理解面向对象-封装继承多态是什么" aria-label="Permalink to &quot;怎么理解面向对象？封装继承多态是什么？&quot;">​</a></h3><ul><li>面向对象就是把现实事物抽象为对象，对象具有属性和行为。</li><li>封装：把事物的属性和行为结合起来，对外隐藏对象的属性，只保留对象提供的接口供外部交互</li><li>继承：是一种子类自动共享父类数据结构和方法的机制，是一种代码复用手段</li><li>多态：是指允许不同类的对象对同意消息做出响应，也就是同一接口，使用不同的实例来执行不同的操作</li></ul><h4 id="多态的体现" tabindex="-1">多态的体现 <a class="header-anchor" href="#多态的体现" aria-label="Permalink to &quot;多态的体现&quot;">​</a></h4><ul><li>方法重载：同一个类中可以有多个同名方法，各自拥有不同的参数列表，根据传入的参数，编译器会决定使用哪一个方法，例如 <code>add(int a, int b)</code> 和 <code>add(double a, double b)</code></li><li>方法重写：在一个父类中定义一个<code>Eat</code> 方法，可以分别在子类<code>Cat</code>和<code>Dog</code>中分别重写这个方法来实现不一样的操作</li><li>接口与实现：多个类可以实现同一个接口</li><li>向上转型和向下转型 <ul><li>向上转型是：<strong>把子类对象赋值给父类类型的引用变量</strong>。</li><li><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 这就是向上转型！把 Guitar 对象，当作 Instrument 来对待。 </span></span>
<span class="line"><span>Instrument myInstrument = new Guitar();</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div></li><li>也就是 可以使用父类类型的引用指向子类对象</li><li>向下转型是： <strong>将父类引用转回其子类类型</strong></li><li><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 向下转型！把泛指的乐器，强行变回吉他</span></span>
<span class="line"><span>Guitar myGuitar = (Guitar) myInstrument; </span></span>
<span class="line"><span>// 可以用吉他专属的技能</span></span>
<span class="line"><span>myGuitar.useWhammyBar();</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div></li></ul></li></ul><h4 id="多态的条件" tabindex="-1">多态的条件 <a class="header-anchor" href="#多态的条件" aria-label="Permalink to &quot;多态的条件&quot;">​</a></h4><ul><li>子类继承父类</li><li>子类重写父类的方法</li><li>父类引用指向子类对象</li></ul><h4 id="多态的实现原理是什么" tabindex="-1">多态的实现原理是什么 <a class="header-anchor" href="#多态的实现原理是什么" aria-label="Permalink to &quot;多态的实现原理是什么&quot;">​</a></h4><ul><li>多态通过动态绑定实现，Java 使用虚方法表存储方法指针，方法调用时根据对象实际类型从虚方法表查找具体实现。</li></ul><h3 id="重载和重写的区别" tabindex="-1">重载和重写的区别 <a class="header-anchor" href="#重载和重写的区别" aria-label="Permalink to &quot;重载和重写的区别&quot;">​</a></h3><ul><li>如果一个类有多个名字相同但参数个数不同的方法，我们通常称这些方法为方法重载。</li><li>如果子类具有和父类一样的方法（参数相同、返回类型相同、方法名相同，但方法体不同），我们称之为方法重写。</li><li>重写是父类和子类中的东西，重载是一个类中的多个同名方法</li></ul><h3 id="抽象类与接口" tabindex="-1">抽象类与接口 <a class="header-anchor" href="#抽象类与接口" aria-label="Permalink to &quot;抽象类与接口&quot;">​</a></h3><h4 id="抽象类" tabindex="-1">抽象类 <a class="header-anchor" href="#抽象类" aria-label="Permalink to &quot;抽象类&quot;">​</a></h4><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 这是一个抽象类（半成品模板），不能直接 new 一个 出来哦！</span></span>
<span class="line"><span>public abstract class BandMember {</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    String name; // 普通属性：大家都有名字</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    public BandMember(String name) {</span></span>
<span class="line"><span>        this.name = name;</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    // 1. 普通方法（已经写好的）：所有成员排练完都会喊累，做法完全一样，直接在模板里写死！</span></span>
<span class="line"><span>    public void complain() {</span></span>
<span class="line"><span>        System.out.println(name + &quot; 说：排练好累呀，好想吃巧克力螺！&quot;);</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    // 2. 抽象方法（留出的空）：大家都会演奏，但怎么演奏？不知道！留给子类自己去实现。</span></span>
<span class="line"><span>    // 注意这里没有大括号 {}，只有分号 ;</span></span>
<span class="line"><span>    public abstract void playMusic(); </span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br></div></div><ul><li>例如可以在支付流程中有这样的一个模板</li></ul><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 支付基础模板（抽象类）</span></span>
<span class="line"><span>public abstract class BasePayment {</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    // 这是一个完整的支付流程！</span></span>
<span class="line"><span>    public void processPayment(double amount) {</span></span>
<span class="line"><span>        checkBalance(amount); // 1. 查余额（大家做法一样）</span></span>
<span class="line"><span>        executePay(amount);   // 2. 真正扣钱（大家做法不一样！去填空吧！）</span></span>
<span class="line"><span>        recordLog();          // 3. 记日志（大家做法一样）</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    // 普通方法：查余额的逻辑对于系统内部是一样的</span></span>
<span class="line"><span>    private void checkBalance(double amount) {</span></span>
<span class="line"><span>        System.out.println(&quot;检查用户账户余额是否大于 &quot; + amount);</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    // 普通方法：记录日志写入数据库也是通用的</span></span>
<span class="line"><span>    private void recordLog() {</span></span>
<span class="line"><span>        System.out.println(&quot;支付完成，将流水写入数据库...&quot;);</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span></span></span>
<span class="line"><span>    // ⭐️ 抽象方法：具体怎么对接微信、支付宝的接口？留给具体的类去写！</span></span>
<span class="line"><span>    protected abstract void executePay(double amount);</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br></div></div><h4 id="接口" tabindex="-1">接口 <a class="header-anchor" href="#接口" aria-label="Permalink to &quot;接口&quot;">​</a></h4><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 只要是消息发送器，就必须能发送消息</span></span>
<span class="line"><span>public interface MessageSender {</span></span>
<span class="line"><span>    void sendMessage(String user, String content);</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 技能实现者 1：短信发送器</span></span>
<span class="line"><span>public class SmsSender implements MessageSender {</span></span>
<span class="line"><span>    @Override</span></span>
<span class="line"><span>    public void sendMessage(String user, String content) {</span></span>
<span class="line"><span>        System.out.println(&quot;调用阿里云短信接口，发送给 &quot; + user + &quot;: &quot; + content);</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 技能实现者 2：邮件发送器</span></span>
<span class="line"><span>public class EmailSender implements MessageSender {</span></span>
<span class="line"><span>    @Override</span></span>
<span class="line"><span>    public void sendMessage(String user, String content) {</span></span>
<span class="line"><span>        System.out.println(&quot;调用腾讯云邮件接口，发送给 &quot; + user + &quot;: &quot; + content);</span></span>
<span class="line"><span>    }</span></span>
<span class="line"><span>}</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br></div></div><h4 id="两者的区别" tabindex="-1">两者的区别 <a class="header-anchor" href="#两者的区别" aria-label="Permalink to &quot;两者的区别&quot;">​</a></h4><ul><li>抽象类强调的是 是什么 的关系，目的在于代码复用；抽象类强调的是 能做什么 的关系，目的在于解决解耦和扩展</li><li>Java 中类只能<strong>单继承</strong>抽象类，但可以<strong>多实现</strong>接口；抽象类是有构造方法的，给子类初始化时调用；而接口没有构造方法；抽象类可以有普通的成员变量，能保存对象的状态；而接口里只能有 <code>public static final</code> 的<strong>全局常量</strong>，不能保存状态</li></ul><h3 id="static-关键字" tabindex="-1">Static 关键字 <a class="header-anchor" href="#static-关键字" aria-label="Permalink to &quot;Static 关键字&quot;">​</a></h3><ul><li>static 关键字可以用来修饰变量、方法、代码块和内部类，以及导入包。</li><li>静态变量：是被Static修饰的变量，属于类，但不属于类的任何一个对象，一个类不管创建多少个对象，静态变量在内存中有且仅有一个副本</li><li>静态方法：是被Static修饰的方法，它不需要 <code>new</code> 出对象，直接用 <code>类名.方法名</code> 就可以调用。静态方法里不能访问非静态成员变量和方法</li><li>静态代码块：只会在类加载的时候才执行一次</li></ul><h3 id="final-关键字" tabindex="-1">final 关键字 <a class="header-anchor" href="#final-关键字" aria-label="Permalink to &quot;final 关键字&quot;">​</a></h3><ul><li><code>final</code>关键字主要有以下三个方面的作用：用于修饰类、方法和变量。</li><li>修饰类：当<code>final</code>修饰一个类时，表示这个类不能被继承。比如，String 类、Integer 类和其他包装类都是用 final 修饰的。</li><li>修饰方法：用<code>final</code>修饰的方法不能在子类中被重写。</li><li>修饰变量：当<code>final</code>修饰基本数据类型的变量时，该变量一旦被赋值就不能再改变。如果是基本数据类型的变量，其数值一旦在初始化之后就不能更改；如果是引用类型的变量，在对其初始化之后就不能再让其指向另一个对象。</li></ul><h3 id="final-finally-finalize-的区别" tabindex="-1">final finally finalize 的区别 <a class="header-anchor" href="#final-finally-finalize-的区别" aria-label="Permalink to &quot;final finally finalize 的区别&quot;">​</a></h3><ul><li>final是一个修饰符</li><li>finally 是异常处理的一部分，用来创建 try 块后面的 finally 块。无论 try 块中的代码是否抛出异常，finally 块中的代码总是会被执行。</li><li>finalize 是Object 类 的一个方法，用于在垃圾回收器将对象从内存中清除出去之前做一些必要的清理工作。</li></ul><h3 id="与-equals-的区别" tabindex="-1">== 与 equals 的区别 <a class="header-anchor" href="#与-equals-的区别" aria-label="Permalink to &quot;== 与 equals 的区别&quot;">​</a></h3><ul><li>= =：用于比较两个对象的引用，即它们是否指向同一个对象实例。如果两个变量引用同一个对象实例，<code>==</code> 返回 <code>true</code>，否则返回 <code>false</code>。</li><li>equals( ) 方法：用于比较两个对象的内容是否相等。默认情况下，<code>equals()</code> 方法的行为与 <code>==</code> 相同，即比较对象引用，但这个方法时常被各种类重写。</li></ul><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>String a = new String(&quot;沉默王二&quot;);</span></span>
<span class="line"><span>String b = new String(&quot;沉默王二&quot;);</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 使用 == 比较</span></span>
<span class="line"><span>System.out.println(a == b); // 输出 false，因为 a 和 b 引用不同的对象</span></span>
<span class="line"><span></span></span>
<span class="line"><span>// 使用 equals() 比较</span></span>
<span class="line"><span>System.out.println(a.equals(b)); // 输出 true，因为 a 和 b 的内容相同</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h3 id="重写equals-方法的时候必须重写-hashcode" tabindex="-1">重写equals 方法的时候必须重写 hashCode？ <a class="header-anchor" href="#重写equals-方法的时候必须重写-hashcode" aria-label="Permalink to &quot;重写equals 方法的时候必须重写 hashCode？&quot;">​</a></h3><ul><li>hashCode主要是用来获取对象的哈希码，哈希码是由对象的内存地址或者是属性计算出来的，是int类型的整数。哈希码是由哈希函数映射而来的，如果让哈希函数将一个较大的输入域映射到一个较小的输出域，那么就可能出现不同的对象拥有相同的哈希码，也就是发送了哈希冲突。</li><li>因此，为了解决哈希冲突的问题，哈希表在处理键时，不仅会比较键对象的哈希码，还会使用 equals 方法来检查键对象是否真正相等。如果两个对象的哈希码相同，但通过 equals 方法比较结果为 false，那么这两个对象就不被视为相等。</li></ul><h3 id="引用类型的变量有什么特点" tabindex="-1">引用类型的变量有什么特点 <a class="header-anchor" href="#引用类型的变量有什么特点" aria-label="Permalink to &quot;引用类型的变量有什么特点&quot;">​</a></h3><ul><li>引用类型的变量存储的是对象的地址，而不是对象本身。因此，引用类型的变量在传递时，传递的是对象的地址，也就是说，传递的是引用的值。</li></ul>`,32)])])}const m=n(p,[["render",i]]);export{d as __pageData,m as default};
